export const allTopics = domains.flatMap((d) =>
  d.topics.map((t) => ({
    ...t,
    domainId: d.id,
    domainName: d.name,
    domainColor: d.color,
    domainIcon: d.icon,
  }))
);

export const allTerms = allTopics.flatMap((t) =>
  (t.keyTerms || []).map((k) => ({
    ...k,
    topicId: t.id,
    topicName: t.name,
    domainName: t.domainName,
    domainColor: t.domainColor,
  }))
);
